// src/services/WebSocketService.js

import { Client } from '@stomp/stompjs';
import SockJS from 'sockjs-client';

const WebSocketService = {
  client: null,
  connected: false,

  connect(onConnectedCallback) {
    if (this.client && this.connected) {
      console.log('🔄 WebSocket already connected');
      if (onConnectedCallback) onConnectedCallback();
      return;
    }

    this.client = new Client({
      webSocketFactory: () => new SockJS('http://localhost:8080/ws'),
      reconnectDelay: 5000,
      heartbeatIncoming: 4000,
      heartbeatOutgoing: 4000,

      onConnect: () => {
        this.connected = true;
        console.log('✅ WebSocket connected');
        if (onConnectedCallback) onConnectedCallback();
      },

      onStompError: (frame) => {
        this.connected = false;
        console.error('❌ STOMP error:', frame);
      },

      onWebSocketError: (error) => {
        this.connected = false;
        console.error('❌ WebSocket connection error:', error);
      },

      onDisconnect: () => {
        this.connected = false;
        console.log('⚠️ WebSocket disconnected');
      },
    });

    this.client.activate();
  },

  disconnect() {
    if (this.client) {
      this.client.deactivate();
      this.connected = false;
      console.log('🔌 WebSocket disconnected');
    }
  },

  subscribe(destination, callback) {
    if (this.client && this.connected) {
      this.client.subscribe(destination, (message) => {
        try {
          const data = JSON.parse(message.body);
          callback(data);
        } catch (err) {
          console.error('❌ Failed to parse message:', err);
        }
      });
      console.log(`📡 Subscribed to ${destination}`);
    } else {
      console.error('❌ WebSocket not connected. Cannot subscribe to', destination);
    }
  },

  send(destination, message) {
    if (this.client && this.connected) {
      this.client.publish({
        destination,
        body: JSON.stringify(message),
      });
      console.log(`📤 Sent message to ${destination}:`, message);
    } else {
      console.error('❌ WebSocket not connected. Cannot send to', destination);
    }
  },

  isConnected() {
    return this.connected;
  },
};

export default WebSocketService;
